from typing import List

def maxArea(height: List[int]) -> int:
    max_area = 0
    left, right = 0, len(height) - 1
    while left < right:
        width = right - left
        h = min(height[left], height[right])
        max_area = max(max_area, width * h)
        if height[left] < height[right]:
            left += 1
        else:
            right -= 1
    return max_area
